  /** 获取目标端点 URL（API Key 附加在 URL 中） */
  getEndpointUrl (baseUrl: string): string {
    // Gemini 的 URL 格式：/v1beta/models/{model}:generateContent
    // 实际 model 名从请求体传入，这里返回基础 URL
    const base = baseUrl.replace(/\/+$/, '')
