/// 确保 Session 有运行中的 Sidecar
#[tauri::command]
pub fn cmd_ensure_session_sidecar(
    manager: State<'_, SidecarManager>,
    session_id: String,
    workspace_path: String,
    owner_type: String,
    owner_id: String,
) -> Result<SidecarInfo, String> {
