/**
 * 协议适配器接口
 *
 * 每个适配器实现此接口，负责在 Anthropic 协议与目标协议之间做双向转换。
 */
export interface ProviderAdapter {
  /** 适配器名称 */
  readonly name: string

  /** 将 Anthropic 请求转为目标格式的请求体 */
  translateRequest (req: AnthropicRequest): unknown

  /** 构建目标 API 的请求头 */
