    }

    // 文本增量
    if (candidate?.content?.parts) {
      for (const part of candidate.content.parts) {
        if (part.text) {
          ctx.outputTokens += Math.ceil(part.text.length / 4)
          events.push({
            type: 'content_block_delta',
            index: ctx.blockIndex,
            delta: { type: 'text_delta', text: part.text },
