/// 编辑文件（查找替换）
fn tool_edit_file(args: &serde_json::Value, workspace: &Path) -> ToolResult {
    let file_path = args.get("path")
        .and_then(|v| v.as_str())
        .unwrap_or("");
    let old_text = args.get("old_text")
        .and_then(|v| v.as_str())
        .unwrap_or("");
    let new_text = args.get("new_text")
        .and_then(|v| v.as_str())
        .unwrap_or("");

    if file_path.is_empty() || old_text.is_empty() {
        return ToolResult {
            success: false,
            output: String::new(),
            error: Some("缺少 path 或 old_text 参数".into()),
        };
    }

    let full_path = workspace.join(file_path);
    match std::fs::read_to_string(&full_path) {
        Ok(content) => {
            if !content.contains(old_text) {
                return ToolResult {
                    success: false,
                    output: String::new(),
                    error: Some("未找到要替换的文本".into()),
                };
            }
            let new_content = content.replacen(old_text, new_text, 1);
            match std::fs::write(&full_path, &new_content) {
                Ok(_) => ToolResult {
                    success: true,
                    output: format!("已编辑 {}", file_path),
                    error: None,
                },
                Err(e) => ToolResult {
                    success: false,
                    output: String::new(),
                    error: Some(format!("写入文件失败: {}", e)),
                },
            }
        }
        Err(e) => ToolResult {
            success: false,
            output: String::new(),
            error: Some(format!("读取文件失败: {}", e)),
        },
    }
}

